1	/**
2	 * Proxy Server
3	 * Runs on localhost and intercepts all Anthropic API calls.
4	 * Your app just needs: ANTHROPIC_BASE_URL=http://localhost:8787
5	 *
6	 * Pipeline per request:
7	 *   1. Deserialize request body
8	 *   2. Check semantic cache → return cached response if hit
9	 *   3. Run prompt optimizer (compression, context trim)
10	 *   4. Run model router (downgrade if appropriate)
11	 *   5. Forward to Anthropic API
12	 *   6. Store response in cache
13	 *   7. Record stats
14	 */
15	
16	import * as http from 'http';
17	import * as https from 'https';
18	import { SemanticCache } from './semanticCache';
19	import { PromptOptimizer } from './promptOptimizer';
20	import { ModelRouter } from './modelRouter';
21	import { TokenCounter, AnthropicRequestBody } from './tokenCounter';
22	import { StatsTracker, RequestStat } from './statsTracker';
23	
24	const ANTHROPIC_HOST = 'api.anthropic.com';
25	
26	export interface ProxyConfig {
27	  port: number;
28	  enabled: boolean;          // master on/off switch — when off, passes through unchanged
29	  enableCache: boolean;
30	  enableCompression: boolean;
31	  enableModelRouter: boolean;
32	  apiKey: string;
33	}
34	
35	export class ProxyServer {
36	  private server: http.Server | null = null;
37	  private cache: SemanticCache;
38	  private optimizer: PromptOptimizer;
39	  private router: ModelRouter;
40	  private tokenCounter: TokenCounter;
41	  private stats: StatsTracker;
42	  private config: ProxyConfig;
43	
44	  constructor(
45	    config: ProxyConfig,
46	    cache: SemanticCache,
47	    optimizer: PromptOptimizer,
48	    router: ModelRouter,
49	    tokenCounter: TokenCounter,
50	    stats: StatsTracker
51	  ) {
52	    this.config = config;
53	    this.cache = cache;
54	    this.optimizer = optimizer;
55	    this.router = router;
56	    this.tokenCounter = tokenCounter;
57	    this.stats = stats;
58	  }
59	
60	  start(): Promise<void> {
61	    return new Promise((resolve, reject) => {
62	      this.server = http.createServer((req, res) => {
63	        console.log(`[Claude Optimizer] >> ${req.method} ${req.url} enabled=${this.config.enabled}`);
64	        this.handleRequest(req, res).catch(err => {
65	          console.error('[Claude Optimizer] Proxy error:', err);
66	          res.writeHead(500, { 'Content-Type': 'application/json' });
67	          res.end(JSON.stringify({ error: { message: 'Proxy internal error', type: 'proxy_error' } }));
68	        });
69	      });
70	
71	      this.server.on('error', (err: any) => {
72	        if (err.code === 'EADDRINUSE') {
73	          reject(new Error(`Port ${this.config.port} is already in use. Change claudeOptimizer.proxyPort in settings.`));
74	        } else {
75	          reject(err);
76	        }
77	      });
78	
79	      this.server.listen(this.config.port, '127.0.0.1', () => {
80	        resolve();
81	      });
82	    });
83	  }
84	
85	  stop(): Promise<void> {
86	    return new Promise((resolve) => {
87	      if (this.server) {
88	        this.server.close(() => resolve());
89	        this.server = null;
90	      } else {
91	        resolve();
92	      }
93	    });
94	  }
95	
96	  isRunning(): boolean {
97	    return this.server !== null && this.server.listening;
98	  }
99	
100	  updateConfig(config: Partial<ProxyConfig>): void {
101	    this.config = { ...this.config, ...config };
102	    this.router.setEnabled(config.enableModelRouter ?? this.config.enableModelRouter);
103	  }
104	
105	  toggle(): boolean {
106	    this.config.enabled = !this.config.enabled;
107	    return this.config.enabled;
108	  }
109	
110	  isEnabled(): boolean {
111	    return this.config.enabled;
112	  }
113	
114	  private async handleRequest(req: http.IncomingMessage, res: http.ServerResponse): Promise<void> {
115	    const rawBody = await readBody(req);
116	
117	    // Master switch OFF → pass through completely unchanged
118	    if (!this.config.enabled) {
119	      this.forwardRaw(req, rawBody, res);
120	      return;
121	    }
122	
123	    const isMessagesEndpoint = req.url?.includes('/messages') || req.url?.includes('/completions');
124	    if (!isMessagesEndpoint || req.method !== 'POST') {
125	      this.forwardRaw(req, rawBody, res);
126	      return;
127	    }
128	
129	    let body: AnthropicRequestBody;
130	    try {
131	      body = JSON.parse(rawBody);
132	    } catch {
133	      this.forwardRaw(req, rawBody, res);
134	      return;
135	    }
136	
137	    // Log incoming request shape for debugging
138	    console.log(`[Claude Optimizer] Incoming: model=${body.model} thinking=${!!body.thinking} beta=${req.headers['anthropic-beta'] || 'none'} stream=${body.stream}`);
139	
140	    // ── OPTIMIZATION PIPELINE ────────────────────────────────────────────────
141	    // Everything below is wrapped in try/catch. If any optimization step fails,
142	    // we fall back to forwarding the sanitized (but otherwise unmodified) request.
143	    const isStreaming = body.stream === true;
144	    let savedByCompression = 0;
145	    let techniques: string[] = [];
146	    let modelDowngraded = false;
147	    const originalModel = body.model;
148	    let optimizedBody = body;
149	
150	    try {
151	      // Token count
152	      const tokenCountResult = this.tokenCounter.countRequest(body);
153	      const originalTokens = tokenCountResult.prompt;
154	      console.log(`[Claude Optimizer] Request tokens: ${originalTokens}`);
155	
156	      // 1. Cache check — only for non-streaming requests
157	      if (this.config.enableCache && !isStreaming) {
158	        const cacheResult = this.cache.lookup(body, originalTokens);
159	        if (cacheResult.hit && cacheResult.response) {
160	          console.log(`[Claude Optimizer] Cache HIT`);
161	          const cacheHitStat = this.buildStat({
162	            body, originalModel: body.model, finalModel: body.model,
163	            inputTokens: originalTokens, outputTokens: cacheResult.response?.usage?.output_tokens ?? 0,
164	            savedByCompression: 0, savedByCache: originalTokens, cacheHit: true,
165	            modelDowngraded: false, techniques: ['cache-hit'],
166	          });
167	          cacheHitStat.savedCostUSD = this.router.estimateCost(body.model, originalTokens, cacheHitStat.outputTokens);
168	          this.stats.record(cacheHitStat);
169	          res.writeHead(200, { 'Content-Type': 'application/json' });
170	          res.end(JSON.stringify(cacheResult.response));
171	          return;
172	        }
173	      }
174	
175	      // 2. Prompt optimization
176	      if (this.config.enableCompression) {
177	        const result = this.optimizer.optimize(body);
178	        optimizedBody = result.body;
179	        savedByCompression = result.savedTokens;
180	        techniques = result.techniques;
181	      }
182	
183	      // 3. Model routing
184	      if (this.config.enableModelRouter) {
185	        const reqApiKey =
186	          (req.headers['x-api-key'] as string | undefined) ||
187	          (req.headers['authorization'] as string | undefined)?.replace(/^Bearer\s+/i, '') ||
188	          this.config.apiKey;
189	        const routing = await this.router.route(optimizedBody, reqApiKey);
190	        optimizedBody.model = routing.selectedModel;
191	        modelDowngraded = routing.downgraded;
192	
193	        // When routing to a model that doesn't support thinking, strip everything related
194	        if (optimizedBody.model.includes('haiku')) {
195	          delete optimizedBody.thinking;
196	          delete optimizedBody.betas;
197	          delete optimizedBody.effort;
198	          // Strip thinking blocks from message history
199	          if (optimizedBody.messages) {
200	            optimizedBody.messages = optimizedBody.messages.map(msg => {
201	              if (!Array.isArray(msg.content)) return msg;
202	              const filtered = msg.content.filter((b: any) =>
203	                b?.type !== 'thinking' && b?.type !== 'redacted_thinking'
204	              );
205	              return filtered.length === msg.content.length ? msg : { ...msg, content: filtered };
206	            });
207	          }
208	          // Scrub thinking betas from headers
209	          if (req.headers['anthropic-beta']) {
210	            const cleaned = (Array.isArray(req.headers['anthropic-beta'])
211	              ? req.headers['anthropic-beta']
212	              : [req.headers['anthropic-beta'] as string])
213	              .flatMap(b => b.split(',').map(s => s.trim()))
214	              .filter(b => !b.toLowerCase().includes('thinking'));
215	            if (cleaned.length > 0) {
216	              req.headers['anthropic-beta'] = cleaned.join(',');
217	            } else {
218	              delete req.headers['anthropic-beta'];
219	            }
220	          }
221	        }
222	        // For non-Haiku models: DON'T touch thinking — the original request had it configured correctly
223	      }
224	    } catch (e) {
225	      // Optimization failed — fall back to sanitized original body
226	      console.error('[Claude Optimizer] Optimization pipeline failed, forwarding original:', e);
227	      optimizedBody = body;
228	    }
229	
230	    // ── FORWARD ──────────────────────────────────────────────────────────────
231	    // If anything goes wrong forwarding the optimized body, fall back to the
232	    // original raw request as an absolute last resort.
233	    try {
234	      if (isStreaming) {
235	        this.forwardStreaming(req, optimizedBody, res, (inputTokens, outputTokens) => {
236	          const finalInputTokens = inputTokens || this.tokenCounter.countRequest(body).prompt;
237	          this.stats.record(this.buildStat({
238	            body: optimizedBody, originalModel, finalModel: optimizedBody.model,
239	            inputTokens: finalInputTokens, outputTokens, savedByCompression,
240	            savedByCache: 0, cacheHit: false, modelDowngraded, techniques,
241	          }));
242	        });
243	      } else {
244	        const response = await this.forwardWithFallback(req, optimizedBody);
245	
246	        // Last resort: if optimized request errored and it was modified, retry with raw
247	        if (response?.error && optimizedBody !== body) {
248	          console.warn('[Claude Optimizer] Optimized request failed, retrying with original');
249	          this.forwardRaw(req, rawBody, res);
250	          return;
251	        }
252	
253	        const inputTokens = response?.usage?.input_tokens ?? this.tokenCounter.countRequest(body).prompt;
254	        const outputTokens = response?.usage?.output_tokens ?? 0;
255	
256	        if (this.config.enableCache && !response?.error) {
257	          this.cache.store(optimizedBody, response, inputTokens);
258	        }
259	        this.stats.record(this.buildStat({
260	          body: optimizedBody, originalModel, finalModel: optimizedBody.model,
261	          inputTokens, outputTokens, savedByCompression,
262	          savedByCache: 0, cacheHit: false, modelDowngraded, techniques,
263	        }));
264	
265	        res.writeHead(200, { 'Content-Type': 'application/json' });
266	        res.end(JSON.stringify(response));
267	      }
268	    } catch (e) {
269	      console.error('[Claude Optimizer] Forward failed, raw passthrough:', e);
270	      this.forwardRaw(req, rawBody, res);
271	    }
272	  }
273	
274	  /**
275	   * Forward non-streaming request, escalating to the next model tier on 400 errors.
276	   * Escalation order: haiku → sonnet → opus
277	   */
278	  private async forwardWithFallback(req: http.IncomingMessage, body: AnthropicRequestBody): Promise<any> {
279	    const MODEL_ESCALATION = ['claude-haiku-4-5-20251001', 'claude-sonnet-4-6', 'claude-opus-4-6'];
280	    let currentBody = body;
281	
282	    while (true) {
283	      const response = await this.forwardToAnthropic(req, currentBody);
284	
285	      // Success — return as-is
286	      if (!response?.error) return response;
287	
288	      // On 400 errors, try escalating to the next model
289	      const currentIdx = MODEL_ESCALATION.indexOf(currentBody.model);
290	      if (currentIdx !== -1 && currentIdx < MODEL_ESCALATION.length - 1) {
291	        const nextModel = MODEL_ESCALATION[currentIdx + 1];
292	        console.warn(`[Claude Optimizer] Model ${currentBody.model} rejected request (${response.error.message?.slice(0, 80)}), escalating to ${nextModel}`);
293	        currentBody = { ...currentBody, model: nextModel };
294	        // Remove thinking/betas when escalating away from haiku too — keep stripping until a model accepts
295	        continue;
296	      }
297	
298	      // No escalation possible — return the error response
299	      return response;
300	    }
301	  }
302	
303	  // Pipe a streaming response — buffers status before committing to client so we can escalate on 400
304	  private forwardStreaming(
305	    req: http.IncomingMessage,
306	    body: AnthropicRequestBody,
307	    res: http.ServerResponse,
308	    onDone: (inputTokens: number, outputTokens: number) => void
309	  ): void {
310	    const MODEL_ESCALATION = ['claude-haiku-4-5-20251001', 'claude-sonnet-4-6', 'claude-opus-4-6'];
311	
312	    const attempt = (currentBody: AnthropicRequestBody): void => {
313	      const bodyStr = JSON.stringify(currentBody);
314	      const headers = this.buildForwardHeaders(req, bodyStr, currentBody.model, currentBody);
315	
316	      const proxyReq = https.request({
317	        hostname: ANTHROPIC_HOST,
318	        port: 443,
319	        path: req.url || '/v1/messages',
320	        method: 'POST',
321	        headers
322	      }, (proxyRes) => {
323	        // On 400, try escalating before committing response headers to client
324	        if (proxyRes.statusCode === 400) {
325	          let errData = '';
326	          proxyRes.on('data', (c: Buffer) => { errData += c.toString(); });
327	          proxyRes.on('end', () => {
328	            let parsed: any = {};
329	            try { parsed = JSON.parse(errData); } catch {}
330	            const currentIdx = MODEL_ESCALATION.indexOf(currentBody.model);
331	            if (currentIdx !== -1 && currentIdx < MODEL_ESCALATION.length - 1) {
332	              const nextModel = MODEL_ESCALATION[currentIdx + 1];
333	              console.warn(`[Claude Optimizer] Streaming: ${currentBody.model} rejected (${parsed?.error?.message?.slice(0, 80)}), escalating to ${nextModel}`);
334	              attempt({ ...currentBody, model: nextModel });
335	            } else {
336	              res.writeHead(400, { 'Content-Type': 'application/json' });
337	              res.end(errData);
338	              onDone(0, 0);
339	            }
340	          });
341	          return;
342	        }
343	
344	        res.writeHead(proxyRes.statusCode || 200, proxyRes.headers);
345	        let buffer = '';
346	        let inputTokens = 0;
347	        let outputTokens = 0;
348	
349	        proxyRes.on('data', (chunk: Buffer) => {
350	          res.write(chunk);
351	          buffer += chunk.toString();
352	          const inputMatch = buffer.match(/"input_tokens":(\d+)/);
353	          const outputMatch = buffer.match(/"output_tokens":(\d+)/);
354	          if (inputMatch) inputTokens = parseInt(inputMatch[1]);
355	          if (outputMatch) outputTokens = parseInt(outputMatch[1]);
356	        });
357	        proxyRes.on('end', () => { res.end(); onDone(inputTokens, outputTokens); });
358	        proxyRes.on('error', () => res.end());
359	      });
360	
361	      proxyReq.on('error', () => { res.writeHead(502); res.end('Bad Gateway'); });
362	      proxyReq.write(bodyStr);
363	      proxyReq.end();
364	    };
365	
366	    attempt(body);
367	  }
368	
369	  private forwardToAnthropic(
370	    req: http.IncomingMessage,
371	    body: AnthropicRequestBody
372	  ): Promise<any> {
373	    return new Promise((resolve, reject) => {
374	      const bodyStr = JSON.stringify(body);
375	      const headers = this.buildForwardHeaders(req, bodyStr, body.model, body);
376	
377	      const proxyReq = https.request({
378	        hostname: ANTHROPIC_HOST, port: 443,
379	        path: req.url || '/v1/messages', method: 'POST', headers
380	      }, (proxyRes) => {
381	        let data = '';
382	        proxyRes.on('data', (chunk: any) => { data += chunk; });
383	        proxyRes.on('end', () => {
384	          try { resolve(JSON.parse(data)); }
385	          catch { resolve(data); }
386	        });
387	      });
388	
389	      proxyReq.on('error', reject);
390	      proxyReq.write(bodyStr);
391	      proxyReq.end();
392	    });
393	  }
394	
395	  // Build headers for forwarding — pass ALL original headers, fix host + content-length
396	  private buildForwardHeaders(req: http.IncomingMessage, bodyStr: string, _targetModel?: string, _body?: AnthropicRequestBody): Record<string, string | string[]> {
397	    const headers: Record<string, string | string[]> = {};
398	    for (const [key, val] of Object.entries(req.headers)) {
399	      if (val !== undefined) headers[key] = val as string | string[];
400	    }
401	    // Force uncompressed responses so we can read error bodies as plain text
402	    headers['accept-encoding'] = 'identity';
403	    headers['host'] = ANTHROPIC_HOST;
404	    headers['content-type'] = 'application/json';
405	    headers['content-length'] = String(Buffer.byteLength(bodyStr));
406	    // Fallback: if no auth header at all, try config key
407	    if (!headers['authorization'] && !headers['x-api-key']) {
408	      const key = this.config.apiKey || process.env.ANTHROPIC_API_KEY || '';
409	      if (key) headers['x-api-key'] = key;
410	    }
411	    // Note: thinking betas are stripped in handleRequest when routing to Haiku.
412	    // Do NOT strip here — the original request needs its betas intact for Sonnet/Opus.
413	    return headers;
414	  }
415	
416	  private forwardRaw(req: http.IncomingMessage, body: string, res: http.ServerResponse): void {
417	    const options: https.RequestOptions = {
418	      hostname: ANTHROPIC_HOST,
419	      port: 443,
420	      path: req.url || '/',
421	      method: req.method,
422	      headers: { ...req.headers, host: ANTHROPIC_HOST }
423	    };
424	
425	    const proxyReq = https.request(options, (proxyRes) => {
426	      res.writeHead(proxyRes.statusCode || 200, proxyRes.headers);
427	      proxyRes.pipe(res);
428	    });
429	
430	    proxyReq.on('error', () => {
431	      res.writeHead(502);
432	      res.end('Bad Gateway');
433	    });
434	
435	    if (body) proxyReq.write(body);
436	    proxyReq.end();
437	  }
438	
439	  private buildStat(params: {
440	    body: AnthropicRequestBody;
441	    originalModel: string;
442	    finalModel: string;
443	    inputTokens: number;
444	    outputTokens: number;
445	    savedByCompression: number;
446	    savedByCache: number;
447	    cacheHit: boolean;
448	    modelDowngraded: boolean;
449	    techniques: string[];
450	  }): RequestStat {
451	    // Cache hits don't incur API costs since they're served from cache
452	    const costUSD = params.cacheHit ? 0 : this.router.estimateCost(params.finalModel, params.inputTokens, params.outputTokens);
453	    const savedCostUSD = this.router.estimateSavings(
454	      params.originalModel,
455	      params.finalModel,
456	      params.inputTokens,
457	      params.outputTokens
458	    ) + (params.savedByCompression / 1_000_000) * 3.0;
459	
460	    return {
461	      timestamp: Date.now(),
462	      model: params.finalModel,
463	      originalModel: params.originalModel,
464	      inputTokens: params.inputTokens,
465	      outputTokens: params.outputTokens,
466	      savedTokensByCompression: params.savedByCompression,
467	      savedTokensByCache: params.savedByCache,
468	      cacheHit: params.cacheHit,
469	      modelDowngraded: params.modelDowngraded,
470	      costUSD,
471	      savedCostUSD,
472	      techniques: params.techniques,
473	    };
474	  }
475	}
476	
477	function readBody(req: http.IncomingMessage): Promise<string> {
478	  return new Promise((resolve, reject) => {
479	    let data = '';
480	    req.on('data', chunk => { data += chunk; });
481	    req.on('end', () => resolve(data));
482	    req.on('error', reject);
483	  });
484	}
