1	/**
2	 * Prompt Optimizer
3	 * Reduces token usage by compressing prompts without losing meaning.
4	 */
5	
6	import { AnthropicRequestBody, TokenCounter } from './tokenCounter';
7	
8	export interface OptimizationResult {
9	  body: AnthropicRequestBody;
10	  originalTokens: number;
11	  optimizedTokens: number;
12	  savedTokens: number;
13	  techniques: string[];
14	}
15	
16	// Max chars to keep in a single tool_result block before truncating
17	const TOOL_RESULT_MAX_CHARS = 8000;
18	// Token budget: if total prompt exceeds this, trim oldest messages
19	const CONTEXT_TOKEN_BUDGET = 40_000;
20	// Minimum messages to always keep (never trim below this)
21	const MIN_MESSAGES_TO_KEEP = 6;
22	
23	export class PromptOptimizer {
24	  constructor(private tokenCounter: TokenCounter) {}
25	
26	  optimize(body: AnthropicRequestBody): OptimizationResult {
27	    const originalTokens = this.tokenCounter.countRequest(body).prompt;
28	    const techniques: string[] = [];
29	
30	    let optimized = JSON.parse(JSON.stringify(body)) as AnthropicRequestBody;
31	
32	    // 1. Normalize whitespace in system prompt
33	    if (optimized.system && typeof optimized.system === 'string') {
34	      const before = optimized.system.length;
35	      optimized.system = this.compressWhitespace(optimized.system);
36	      if (optimized.system.length < before) {
37	        techniques.push('whitespace-compression');
38	      }
39	    }
40	
41	    // 2. Compress each message — handle both string and array content
42	    for (let i = 0; i < optimized.messages.length; i++) {
43	      const msg = optimized.messages[i];
44	      if (typeof msg.content === 'string') {
45	        const before = msg.content;
46	        msg.content = this.compressWhitespace(msg.content);
47	        msg.content = this.removeRedundantPhrases(msg.content);
48	        if (msg.content !== before && !techniques.includes('whitespace-compression')) {
49	          techniques.push('whitespace-compression');
50	        }
51	      } else if (Array.isArray(msg.content)) {
52	        let changed = false;
53	        msg.content = msg.content.map((block: any) => {
54	          if (!block || typeof block !== 'object') return block;
55	
56	          // text blocks: compress whitespace + filler
57	          if (block.type === 'text' && typeof block.text === 'string') {
58	            const before = block.text;
59	            block = { ...block, text: this.compressWhitespace(block.text) };
60	            block = { ...block, text: this.removeRedundantPhrases(block.text) };
61	            if (block.text !== before) changed = true;
62	          }
63	
64	          // tool_result blocks: truncate oversized content
65	          if (block.type === 'tool_result') {
66	            block = this.trimToolResult(block);
67	            changed = true;
68	          }
69	
70	          return block;
71	        });
72	        if (changed && !techniques.includes('whitespace-compression')) {
73	          techniques.push('whitespace-compression');
74	        }
75	      }
76	    }
77	
78	    // 3. Trim tool_result in assistant messages (tool_use results embedded in content)
79	    //    Already handled above, but also check for nested tool results
80	    optimized = this.trimOversizedToolResults(optimized, techniques);
81	
82	    // 4. Context window trim — token-budget based, not message-count based
83	    const tokensAfterCompression = this.tokenCounter.countRequest(optimized).prompt;
84	    if (tokensAfterCompression > CONTEXT_TOKEN_BUDGET) {
85	      optimized = this.trimContextByTokens(optimized, CONTEXT_TOKEN_BUDGET);
86	      techniques.push('context-trim');
87	    }
88	
89	    // 5. Deduplicate repeated code blocks
90	    optimized = this.deduplicateContent(optimized, techniques);
91	
92	    const optimizedTokens = this.tokenCounter.countRequest(optimized).prompt;
93	    const savedTokens = Math.max(0, originalTokens - optimizedTokens);
94	
95	    return { body: optimized, originalTokens, optimizedTokens, savedTokens, techniques };
96	  }
97	
98	  private compressWhitespace(text: string): string {
99	    return text
100	      .replace(/\r\n/g, '\n')           // normalize line endings
101	      .replace(/\n{3,}/g, '\n\n')       // max 2 consecutive blank lines
102	      .replace(/[ \t]{2,}/g, ' ')       // collapse multiple spaces/tabs
103	      .replace(/^\s+|\s+$/g, '')        // trim leading/trailing
104	      .trim();
105	    // NOTE: intentionally NOT stripping indentation (/\n +/g) — that breaks code blocks
106	  }
107	
108	  private removeRedundantPhrases(text: string): string {
109	    const fillers = [
110	      /^(Sure,?\s+|Of course,?\s+|Certainly,?\s+|Absolutely,?\s+)/gi,
111	      /^(I'd be happy to help you with that\.?\s*)/gi,
112	      /^(As an AI language model,?\s+)/gi,
113	      /^(As a helpful assistant,?\s+)/gi,
114	      /(Is there anything else I can help you with\??\s*)$/gi,
115	      /(Let me know if you (need|have) any (more |other )?questions\.?\s*)$/gi,
116	      /(Feel free to ask if you need (more |further )?clarification\.?\s*)$/gi,
117	    ];
118	
119	    let result = text;
120	    for (const pattern of fillers) {
121	      result = result.replace(pattern, '');
122	    }
123	    return result.trim();
124	  }
125	
126	  /**
127	   * Truncate a tool_result block whose content exceeds TOOL_RESULT_MAX_CHARS.
128	   * Keeps the first half and last quarter so the model still sees context + outcome.
129	   */
130	  private trimToolResult(block: any): any {
131	    if (!block || block.type !== 'tool_result') return block;
132	
133	    if (typeof block.content === 'string') {
134	      if (block.content.length > TOOL_RESULT_MAX_CHARS) {
135	        const keep = TOOL_RESULT_MAX_CHARS;
136	        const head = Math.floor(keep * 0.6);
137	        const tail = keep - head;
138	        block = {
139	          ...block,
140	          content:
141	            block.content.slice(0, head) +
142	            `\n...[truncated ${block.content.length - keep} chars]...\n` +
143	            block.content.slice(-tail),
144	        };
145	      }
146	    } else if (Array.isArray(block.content)) {
147	      block = {
148	        ...block,
149	        content: block.content.map((inner: any) => {
150	          if (inner?.type === 'text' && typeof inner.text === 'string' && inner.text.length > TOOL_RESULT_MAX_CHARS) {
151	            const keep = TOOL_RESULT_MAX_CHARS;
152	            const head = Math.floor(keep * 0.6);
153	            const tail = keep - head;
154	            return {
155	              ...inner,
156	              text:
157	                inner.text.slice(0, head) +
158	                `\n...[truncated ${inner.text.length - keep} chars]...\n` +
159	                inner.text.slice(-tail),
160	            };
161	          }
162	          return inner;
163	        }),
164	      };
165	    }
166	
167	    return block;
168	  }
169	
170	  /**
171	   * Walk all messages and trim any tool_result blocks that are still oversized.
172	   * This catches cases where tool results are embedded inside assistant messages.
173	   */
174	  private trimOversizedToolResults(body: AnthropicRequestBody, techniques: string[]): AnthropicRequestBody {
175	    let trimmed = false;
176	    const messages = body.messages.map((msg) => {
177	      if (!Array.isArray(msg.content)) return msg;
178	      const newContent = msg.content.map((block: any) => {
179	        if (block?.type === 'tool_result') {
180	          const before = JSON.stringify(block).length;
181	          const after = this.trimToolResult(block);
182	          if (JSON.stringify(after).length < before) trimmed = true;
183	          return after;
184	        }
185	        return block;
186	      });
187	      return { ...msg, content: newContent };
188	    });
189	
190	    if (trimmed && !techniques.includes('tool-result-trim')) {
191	      techniques.push('tool-result-trim');
192	    }
193	
194	    return { ...body, messages };
195	  }
196	
197	  /**
198	   * Remove oldest messages until we're under the token budget.
199	   * Always keeps at least MIN_MESSAGES_TO_KEEP recent messages.
200	   * Ensures tool_use/tool_result pairs are never split.
201	   * Prepends a context note so the model knows history was trimmed.
202	   */
203	  private trimContextByTokens(body: AnthropicRequestBody, budget: number): AnthropicRequestBody {
204	    let messages = [...body.messages];
205	
206	    while (messages.length > MIN_MESSAGES_TO_KEEP) {
207	      const testBody = { ...body, messages };
208	      if (this.tokenCounter.countRequest(testBody).prompt <= budget) break;
209	      messages = messages.slice(1); // drop oldest
210	      // After dropping, strip any orphaned tool_result blocks at the new head.
211	      // An orphaned tool_result has no preceding tool_use in the remaining messages.
212	      messages = this.stripOrphanedToolResults(messages);
213	    }
214	
215	    const droppedCount = body.messages.length - messages.length;
216	    if (droppedCount > 0) {
217	      const summaryMsg = {
218	        role: 'user' as const,
219	        content: `[Context note: ${droppedCount} earlier messages were trimmed to save tokens. The conversation continues below.]`,
220	      };
221	      messages = [summaryMsg, ...messages];
222	    }
223	
224	    return { ...body, messages };
225	  }
226	
227	  /**
228	   * Remove tool_result blocks from the first user message if their tool_use_id
229	   * has no corresponding tool_use in the remaining messages.
230	   */
231	  private stripOrphanedToolResults(messages: AnthropicRequestBody['messages']): AnthropicRequestBody['messages'] {
232	    if (messages.length === 0) return messages;
233	
234	    // Collect all tool_use ids present in the remaining messages
235	    const validToolUseIds = new Set<string>();
236	    for (const msg of messages) {
237	      if (Array.isArray(msg.content)) {
238	        for (const block of msg.content) {
239	          if (block?.type === 'tool_use' && block.id) {
240	            validToolUseIds.add(block.id);
241	          }
242	        }
243	      }
244	    }
245	
246	    // Strip orphaned tool_result blocks from the first message
247	    const first = messages[0];
248	    if (!Array.isArray(first.content)) return messages;
249	
250	    const cleaned = first.content.filter((block: any) => {
251	      if (block?.type === 'tool_result') {
252	        return validToolUseIds.has(block.tool_use_id);
253	      }
254	      return true;
255	    });
256	
257	    if (cleaned.length === first.content.length) return messages; // nothing removed
258	
259	    // If the first message is now empty, drop it entirely
260	    if (cleaned.length === 0) return messages.slice(1);
261	
262	    return [{ ...first, content: cleaned }, ...messages.slice(1)];
263	  }
264	
265	  private deduplicateContent(body: AnthropicRequestBody, techniques: string[]): AnthropicRequestBody {
266	    const seen = new Map<string, number>();
267	    let deduped = false;
268	
269	    const messages = body.messages.map((msg, idx) => {
270	      const compressContent = (text: string): string => {
271	        const blocks = text.match(/```[\s\S]{100,}?```/g) || [];
272	        let result = text;
273	        for (const block of blocks) {
274	          const hash = simpleHash(block);
275	          if (seen.has(hash)) {
276	            result = result.replace(block, `[same code as message ${seen.get(hash)! + 1}]`);
277	            deduped = true;
278	          } else {
279	            seen.set(hash, idx);
280	          }
281	        }
282	        return result;
283	      };
284	
285	      if (typeof msg.content === 'string') {
286	        return { ...msg, content: compressContent(msg.content) };
287	      } else if (Array.isArray(msg.content)) {
288	        const newContent = msg.content.map((block: any) => {
289	          if (block?.type === 'text' && typeof block.text === 'string') {
290	            return { ...block, text: compressContent(block.text) };
291	          }
292	          return block;
293	        });
294	        return { ...msg, content: newContent };
295	      }
296	      return msg;
297	    });
298	
299	    if (deduped && !techniques.includes('content-dedup')) {
300	      techniques.push('content-dedup');
301	    }
302	
303	    return { ...body, messages };
304	  }
305	
306	  optimizeSystemPrompt(systemPrompt: string): string {
307	    let optimized = this.compressWhitespace(systemPrompt);
308	    const sentences = optimized.split(/\.\s+/);
309	    const unique = [...new Set(sentences)];
310	    optimized = unique.join('. ');
311	    return optimized;
312	  }
313	}
314	
315	function simpleHash(str: string): string {
316	  let hash = 0;
317	  for (let i = 0; i < str.length; i++) {
318	    const char = str.charCodeAt(i);
319	    hash = ((hash << 5) - hash) + char;
320	    hash = hash & hash;
321	  }
322	  return hash.toString(36);
323	}
