1	/**
2	 * Model Router
3	 * Uses Haiku as a cheap classifier to pick the right model for each request.
4	 *
5	 * Waterfall:  Haiku → Sonnet → Opus
6	 *   simple   → Haiku   (greetings, short Q&A, trivial tasks)
7	 *   moderate → Sonnet  (coding, analysis, debugging, explanation)
8	 *   complex  → Opus    (deep architecture, multi-system reasoning)
9	 *
10	 * Only the last user message is sent to the classifier — never the full context.
11	 */
12	
13	import * as https from 'https';
14	import { AnthropicRequestBody } from './tokenCounter';
15	
16	export interface RoutingDecision {
17	  originalModel: string;
18	  selectedModel: string;
19	  reason: string;
20	  downgraded: boolean;
21	}
22	
23	export interface ModelRouterConfig {
24	  enabled: boolean;
25	  apiKey?: string;
26	  minimumModel?: string;
27	  allowOpus?: boolean;   // default false — Opus is very expensive
28	}
29	
30	// Model pricing per 1M tokens (input / output)
31	const MODEL_COSTS: Record<string, { input: number; output: number }> = {
32	  'claude-haiku-4-5-20251001': { input: 0.80,  output: 4.00  },
33	  'claude-haiku-4-5':          { input: 0.80,  output: 4.00  },
34	  'claude-sonnet-4-6':         { input: 3.00,  output: 15.00 },
35	  'claude-opus-4-6':           { input: 15.00, output: 75.00 },
36	};
37	
38	const MODEL_HIERARCHY = ['claude-haiku-4-5-20251001', 'claude-sonnet-4-6', 'claude-opus-4-6'];
39	
40	const CLASSIFIER_PROMPT = `Classify the complexity of this user request. Reply with ONLY one word:
41	
42	simple   = greeting, thanks, trivial yes/no, one-liner
43	moderate = coding task, debugging, explanation, analysis, file edits
44	complex  = multi-system architecture, deep research, very long multi-step implementation
45	
46	Request: "{{MESSAGE}}"
47	
48	Reply:`;
49	
50	export class ModelRouter {
51	  private config: ModelRouterConfig;
52	  private routingLog: RoutingDecision[] = [];
53	
54	  constructor(config: ModelRouterConfig | boolean = true) {
55	    if (typeof config === 'boolean') {
56	      this.config = { enabled: config };
57	    } else {
58	      this.config = config;
59	    }
60	  }
61	
62	  async route(body: AnthropicRequestBody, requestApiKey?: string): Promise<RoutingDecision> {
63	    const originalModel = body.model;
64	
65	    if (!this.config.enabled) {
66	      const result: RoutingDecision = { originalModel, selectedModel: originalModel, reason: 'routing disabled', downgraded: false };
67	      this.routingLog.push(result);
68	      return result;
69	    }
70	
71	    const decision = await this.decide(body, requestApiKey);
72	    const result: RoutingDecision = { originalModel, ...decision };
73	    this.routingLog.push(result);
74	    return result;
75	  }
76	
77	  private async decide(body: AnthropicRequestBody, requestApiKey?: string): Promise<Omit<RoutingDecision, 'originalModel'>> {
78	    const originalModel = body.model;
79	    const lastMessage = this.extractLastUserMessage(body);
80	
81	    // No message text — keep original
82	    if (!lastMessage.trim()) {
83	      return { selectedModel: originalModel, reason: 'no message text', downgraded: false };
84	    }
85	
86	    // Classify via Haiku — prefer key from the incoming request so the proxy
87	    // works even when claudeOptimizer.anthropicApiKey is not configured in settings
88	    const apiKey = requestApiKey || this.config.apiKey || process.env.ANTHROPIC_API_KEY || '';
89	    if (!apiKey) {
90	      return { selectedModel: originalModel, reason: 'no api key for classifier', downgraded: false };
91	    }
92	
93	    let complexity: 'simple' | 'moderate' | 'complex';
94	    try {
95	      complexity = await withTimeout(this.classify(lastMessage, apiKey), 2000);
96	    } catch (err) {
97	      console.warn('[ModelRouter] Classifier skipped (timeout or error):', (err as Error).message);
98	      return { selectedModel: originalModel, reason: 'classifier skipped', downgraded: false };
99	    }
100	
101	    const targetModel = this.complexityToModel(complexity);
102	    const finalModel = this.applyConstraints(targetModel, originalModel);
103	    const downgraded = this.modelRank(finalModel) < this.modelRank(originalModel);
104	
105	    return {
106	      selectedModel: finalModel,
107	      reason: `classifier: ${complexity}`,
108	      downgraded,
109	    };
110	  }
111	
112	  private async classify(message: string, apiKey: string): Promise<'simple' | 'moderate' | 'complex'> {
113	    const prompt = CLASSIFIER_PROMPT.replace('{{MESSAGE}}', message.slice(0, 500)); // cap at 500 chars
114	
115	    const requestBody = JSON.stringify({
116	      model: 'claude-haiku-4-5-20251001',
117	      max_tokens: 5,
118	      messages: [{ role: 'user', content: prompt }],
119	    });
120	
121	    const raw = await httpsPost('api.anthropic.com', '/v1/messages', apiKey, requestBody);
122	    const response = JSON.parse(raw);
123	    const text = (response?.content?.[0]?.text || '').trim().toLowerCase();
124	
125	    if (text.startsWith('simple'))   return 'simple';
126	    if (text.startsWith('complex'))  return 'complex';
127	    return 'moderate'; // default to moderate if unclear
128	  }
129	
130	  private complexityToModel(complexity: 'simple' | 'moderate' | 'complex'): string {
131	    switch (complexity) {
132	      case 'simple':   return 'claude-haiku-4-5-20251001';
133	      case 'moderate': return 'claude-sonnet-4-6';
134	      case 'complex':  return this.config.allowOpus ? 'claude-opus-4-6' : 'claude-sonnet-4-6';
135	    }
136	  }
137	
138	  private applyConstraints(targetModel: string, _originalModel: string): string {
139	    // Enforce minimum model floor if set
140	    if (this.config.minimumModel) {
141	      if (this.modelRank(this.config.minimumModel) > this.modelRank(targetModel)) {
142	        return this.config.minimumModel;
143	      }
144	    }
145	    return targetModel;
146	  }
147	
148	  private modelRank(model: string): number {
149	    // Higher rank = more capable
150	    const idx = MODEL_HIERARCHY.indexOf(model);
151	    return idx === -1 ? 1 : idx; // unknown models default to sonnet rank
152	  }
153	
154	  private extractLastUserMessage(body: AnthropicRequestBody): string {
155	    const lastUser = [...body.messages].reverse().find(m => m.role === 'user');
156	    if (!lastUser) return '';
157	
158	    if (typeof lastUser.content === 'string') return lastUser.content;
159	
160	    if (Array.isArray(lastUser.content)) {
161	      return lastUser.content
162	        .filter((b: any) => b?.type === 'text')
163	        .map((b: any) => b.text)
164	        .join(' ');
165	    }
166	
167	    return '';
168	  }
169	
170	  estimateCost(model: string, inputTokens: number, outputTokens: number): number {
171	    const costs = MODEL_COSTS[model] || MODEL_COSTS['claude-sonnet-4-6'];
172	    return (inputTokens / 1_000_000) * costs.input + (outputTokens / 1_000_000) * costs.output;
173	  }
174	
175	  estimateSavings(originalModel: string, routedModel: string, inputTokens: number, outputTokens: number): number {
176	    return Math.max(0, this.estimateCost(originalModel, inputTokens, outputTokens) - this.estimateCost(routedModel, inputTokens, outputTokens));
177	  }
178	
179	  getStats() {
180	    const downgrades = this.routingLog.filter(r => r.downgraded).length;
181	    return {
182	      totalRouted: this.routingLog.length,
183	      downgrades,
184	      downgradeRate: this.routingLog.length > 0 ? (downgrades / this.routingLog.length) * 100 : 0,
185	      log: this.routingLog.slice(-50),
186	    };
187	  }
188	
189	  setEnabled(enabled: boolean): void {
190	    this.config.enabled = enabled;
191	  }
192	
193	  setConfig(config: Partial<ModelRouterConfig>): void {
194	    this.config = { ...this.config, ...config };
195	  }
196	}
197	
198	function withTimeout<T>(promise: Promise<T>, ms: number): Promise<T> {
199	  return Promise.race([
200	    promise,
201	    new Promise<T>((_, reject) => setTimeout(() => reject(new Error(`timeout after ${ms}ms`)), ms)),
202	  ]);
203	}
204	
205	function httpsPost(hostname: string, path: string, apiKey: string, body: string): Promise<string> {
206	  return new Promise((resolve, reject) => {
207	    const req = https.request({
208	      hostname,
209	      port: 443,
210	      path,
211	      method: 'POST',
212	      headers: {
213	        'Content-Type': 'application/json',
214	        'Content-Length': Buffer.byteLength(body),
215	        'x-api-key': apiKey,
216	        'anthropic-version': '2023-06-01',
217	      },
218	    }, (res) => {
219	      let data = '';
220	      res.on('data', chunk => { data += chunk; });
221	      res.on('end', () => resolve(data));
222	    });
223	    req.on('error', reject);
224	    req.write(body);
225	    req.end();
226	  });
227	}
