1	/**
2	 * Token Counter
3	 * Estimates token counts for Claude messages using cl100k_base encoding.
4	 * Claude uses a BPE tokenizer similar to GPT-4; this gives a close estimate.
5	 */
6	
7	export interface TokenCount {
8	  prompt: number;
9	  estimated: boolean;
10	}
11	
12	// Simple regex-based tokenizer for environments where tiktoken isn't available
13	function roughTokenCount(text: any): number {
14	  if (!text) return 0;
15	  const str = typeof text === 'string' ? text : JSON.stringify(text);
16	  const words = str.split(/\s+/).length;
17	  const chars = str.length;
18	  return Math.ceil((words * 1.3 + chars / 5) / 2);
19	}
20	
21	export class TokenCounter {
22	  private encoder: any = null;
23	  private ready = false;
24	
25	  async init(): Promise<void> {
26	    try {
27	      // Try to load tiktoken for accurate counts
28	      const tiktoken = await import('tiktoken');
29	      this.encoder = tiktoken.get_encoding('cl100k_base');
30	      this.ready = true;
31	    } catch {
32	      // Fallback to rough estimate
33	      this.ready = false;
34	    }
35	  }
36	
37	  count(text: string): TokenCount {
38	    if (this.ready && this.encoder) {
39	      try {
40	        const tokens = this.encoder.encode(text);
41	        return { prompt: tokens.length, estimated: false };
42	      } catch {
43	        return { prompt: roughTokenCount(text), estimated: true };
44	      }
45	    }
46	    return { prompt: roughTokenCount(text), estimated: true };
47	  }
48	
49	  countMessages(messages: Array<{ role: string; content: string | any[] }>): TokenCount {
50	    let total = 0;
51	    // Claude API overhead per message
52	    const PER_MESSAGE_OVERHEAD = 4;
53	    const BASE_OVERHEAD = 3;
54	
55	    for (const msg of messages) {
56	      const text = typeof msg.content === 'string' ? msg.content : JSON.stringify(msg.content);
57	      const count = this.count(text);
58	      total += count.prompt + PER_MESSAGE_OVERHEAD;
59	    }
60	    total += BASE_OVERHEAD;
61	
62	    return { prompt: total, estimated: !this.ready };
63	  }
64	
65	  countRequest(body: AnthropicRequestBody): TokenCount {
66	    let total = 0;
67	
68	    if (body.system) {
69	      const sys = typeof body.system === 'string' ? body.system : JSON.stringify(body.system);
70	      total += this.count(sys).prompt;
71	    }
72	
73	    if (body.messages) {
74	      total += this.countMessages(body.messages).prompt;
75	    }
76	
77	    return { prompt: total, estimated: !this.ready };
78	  }
79	
80	  dispose(): void {
81	    if (this.encoder) {
82	      try {
83	        this.encoder.free();
84	      } catch {}
85	    }
86	  }
87	}
88	
89	export interface AnthropicRequestBody {
90	  model: string;
91	  messages: Array<{ role: string; content: string | any[] }>;
92	  system?: string | any[];
93	  max_tokens?: number;
94	  temperature?: number;
95	  stream?: boolean;
96	  [key: string]: any;
97	}
