// ── SANITIZE ─────────────────────────────────────────────────────────────
// Ensure thinking/strategy consistency: strategy requires thinking enabled.
// If thinking was stripped (e.g. Haiku downgrade) but strategy survived, remove it.
const thinkingEnabled = optimizedBody.thinking &&
  (optimizedBody.thinking.type === 'enabled' || optimizedBody.thinking.type === 'adaptive');
if (!thinkingEnabled) {
  delete optimizedBody.strategy;
  // Also strip thinking if it exists but isn't enabled/adaptive (e.g. type: "disabled")
  if (optimizedBody.thinking && optimizedBody.thinking.type !== 'enabled' && optimizedBody.thinking.type !== 'adaptive') {
    delete optimizedBody.thinking;
  }
  // Strip thinking betas from headers if thinking isn't active
  if (req.headers['anthropic-beta']) {
    const cleaned = (Array.isArray(req.headers['anthropic-beta'])
      ? req.headers['anthropic-beta']
      : [req.headers['anthropic-beta'] as string])
      .flatMap(b => b.split(',').map(s => s.trim()))
      .filter(b => !b.toLowerCase().includes('thinking'));
    if (cleaned.length > 0) {
      req.headers['anthropic-beta'] = cleaned.join(',');
    } else {
      delete req.headers['anthropic-beta'];
    }
  }
}

